SELECT beaconid
FROM beacons
WHERE status = 'active';

SELECT MAX(max_value) AS max_temp_threshold
FROM environmental_metrics
WHERE metric_name = 'temperature';

SELECT * 
FROM environmental_metrics
ORDER BY max_value DESC;

SELECT location_name 
FROM beacons 
WHERE battery_level = (SELECT MAX(battery_level) FROM beacons);
